import React, { useMemo, useState } from 'react';
import {
  Input,
  Select,
  Modal, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { masterService } from '../../../services/master/masterService';
import type { CustomerDto, CustomerGroupDto } from '../../../services/master/models';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListGrid,
  CatalogCodeReplaceProvider,
  CatalogListCodeCell,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { CustomerForm } from '../../../components/dm/CustomerForm';
import {
  buildCustomerGroupSelectOptions,
  CUSTOMER_TYPE_LABELS,
} from '../../../utils/customerGroupTree';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-doi-tuong';
const CATALOG_KIND = 'customers';

const DoiTuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [customerGroupFilter, setCustomerGroupFilter] = useState('');
  const [customerGroups, setCustomerGroups] = useState<CustomerGroupDto[]>([]);
  const [items, setItems] = useState<CustomerDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CustomerDto | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);

  const { customerGroupOptions: listGroupOptions } = useVoucherInitData('customer-list');
  const initFormName = modalOpen && editing ? 'edit-customer' : 'create-customer';

  const groupOpts = useMemo(() => {
    if (listGroupOptions.length > 0) return listGroupOptions;
    return buildCustomerGroupSelectOptions(customerGroups);
  }, [listGroupOptions, customerGroups]);

  const filterGroupOpts = useMemo(() => {
    if (listGroupOptions.length > 0) return listGroupOptions;
    return buildCustomerGroupSelectOptions(customerGroups);
  }, [listGroupOptions, customerGroups]);

  const groupById = useMemo(() => {
    const map = new Map<string, CustomerGroupDto>();
    for (const g of customerGroups) map.set(g.customerGroupId, g);
    return map;
  }, [customerGroups]);

  const groupLabel = (customerGroupId?: string) => {
    if (!customerGroupId) return '—';
    const g = groupById.get(customerGroupId);
    return g ? `${g.code} — ${g.name}` : '—';
  };

  const typeLabel = (customerGroupId?: string, customerType?: string) => {
    const g = customerGroupId ? groupById.get(customerGroupId) : undefined;
    const t = g?.customerType ?? customerType;
    return t ? (CUSTOMER_TYPE_LABELS[t] ?? t) : '—';
  };

  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  type CustomerGridRow = CustomerDto & { id: string };
  const gridRows = useMemo<CustomerGridRow[]>(
    () => items.map(r => ({ ...r, id: r.customerId })),
    [items],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.customerId,
    isRowSelectable: () => true,
  });

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getCustomerGroups({ page: 1, pageSize: 500 })
        .then(data => { if (!cancelled) setCustomerGroups(data.items); })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [reloadKey]);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getCustomers({
        search: search || undefined,
        customerGroupId: customerGroupFilter || undefined,
        page,
        pageSize,
      })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục đối tượng', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, customerGroupFilter, page, pageSize, reloadKey, dispatch]);

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: CustomerDto) => {
    setViewOnlyShared(isSharedCatalogReadOnly(row));
    setEditing(row);
    markClean();
    setModalOpen(true);
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.customerId)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.customerId === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.customerId === id)!;
        return masterService.updateCustomer(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} đối tượng`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteCustomer(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} đối tượng`, type: 'success' });
    }
    refresh();
  };

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        canAdd={groupOpts.length > 0}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Danh mục đối tượng', titleIconClass: 'fas fa-handshake' }}
        listTitle="Danh sách đối tượng"
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-customerGroupFilter`}>
              <Select
                value={customerGroupFilter}
                placeholder="Tất cả nhóm"
                className={selectPlaceholderClass(customerGroupFilter)}
                onChange={e => { setCustomerGroupFilter(e.target.value); resetPage(); selection.clearSelection(); }}
                options={filterGroupOpts}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch hideRefresh />
          </CatalogListHeaderFilters>
        )}
        extraModals={<LeaveConfirmModal {...leaveConfirmModalProps} />}
      >
        {items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.customerId}
            headerCells={(
              <>
                <th>Mã</th>
                <th>Tên đối tượng</th>
                <CatalogCompanyTh />
                <th>Nhóm</th>
                <th>Loại</th>
                <th>Mã số thuế</th>
                <th>SĐT</th>
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => (
              <>
                <CatalogListCodeCell testIdPrefix={TEST_ID} code={r.code} />
                <td>{r.name}</td>
                <CatalogCompanyTd label={r.companyName} />
                <td>{groupLabel(r.customerGroupId)}</td>
                <td><span className={styles.tagDefault}>{typeLabel(r.customerGroupId, r.customerType)}</span></td>
                <td>{r.taxCode ?? '—'}</td>
                <td>{r.phone ?? '—'}</td>
                <td>
                  <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                    {r.isActive ? 'Dùng' : 'Ngưng'}
                  </span>
                </td>
              </>
            )}
          />
        )}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem đối tượng dùng chung' : editing ? 'Sửa đối tượng' : 'Thêm đối tượng'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          {modalOpen && (
            <CustomerForm
              key={editing?.customerId ?? 'create'}
              testIdPrefix={TEST_ID}
              editing={editing}
              initFormName={initFormName}
              listGroupOptions={listGroupOptions}
              companyName={editing?.companyName ?? sessionCompanyName}
              sharedCatalog={sharedForm}
              readOnly={viewOnlyShared}
              onDirtyChange={onDirtyChange}
              onCancel={closeFormModal}
              onSaved={() => {
                setModalOpen(false);
                refresh();
              }}
              onValidationFailed={() => scrollToFirstFieldError(TEST_ID)}
            />
          )}
        </div>
      </Modal>
    </CatalogCodeReplaceProvider>
  );
};

export default DoiTuongPage;
